using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    // --- CreateOrder: happy-path ---

    [TestMethod]
    public void CreateOrder_WithSingleItem_ReturnsOrderWithCorrectTotal()
    {
        var items = CreateItems(("Widget", 9.99m, 2));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(19.98m, order.Total);
        Assert.AreEqual(1, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_ReturnsSumOfAllItems()
    {
        var items = CreateItems(("A", 10m, 1), ("B", 5m, 3));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(25m, order.Total); // 10*1 + 5*3
    }

    [TestMethod]
    public void CreateOrder_AssignsNonEmptyId()
    {
        var items = CreateItems(("Widget", 1m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsFalse(string.IsNullOrWhiteSpace(order.Id));
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;

        var order = _sut.CreateOrder("cust-1", CreateItems(("W", 1m, 1)));

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_StoresOrderForLaterRetrieval()
    {
        var order = _sut.CreateOrder("cust-1", CreateItems(("W", 1m, 1)));

        var retrieved = _sut.GetOrder(order.Id);

        Assert.AreSame(order, retrieved);
    }

    // --- CreateOrder: validation ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("W", 1m, 1));

        Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(() => _sut.CreateOrder("cust-1", []));
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsOrder()
    {
        var order = _sut.CreateOrder("cust-1", CreateItems(("W", 1m, 1)));

        var result = _sut.GetOrder(order.Id);

        Assert.IsNotNull(result);
        Assert.AreEqual(order.Id, result.Id);
    }

    [TestMethod]
    public void GetOrder_UnknownId_ReturnsNull()
    {
        var result = _sut.GetOrder("nonexistent");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        _sut.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        _sut.CreateOrder("cust-2", CreateItems(("B", 2m, 1)));
        _sut.CreateOrder("cust-1", CreateItems(("C", 3m, 1)));

        var results = _sut.GetOrdersByCustomer("cust-1");

        Assert.AreEqual(2, results.Count);
        Assert.IsTrue(results.All(o => o.CustomerId == "cust-1"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_UnknownCustomer_ReturnsEmptyList()
    {
        _sut.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));

        var results = _sut.GetOrdersByCustomer("unknown");

        Assert.AreEqual(0, results.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ResultIsReadOnly()
    {
        _sut.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));

        var results = _sut.GetOrdersByCustomer("cust-1");

        Assert.IsInstanceOfType<IReadOnlyList<Order>>(results);
    }
}

